const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      const premium = step.items.reduce(
        (sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0),
        PROCESSING_FEE
      );
      return { premium };
    }
  });
  return { results };
}

