    it.todo("adds 50% cursed surcharge on the cursed item's base premium only");
    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
    it.todo("applies both cursed and high-enchantment surcharges on the same item");
    it.todo("does not add high-enchantment surcharge for enchantment level 4");
    it.todo("applies item-specific surcharges only to affected items in multi-item policy");
  });

  describe("Quote - policy-wide modifiers", () => {
    it.todo("adds 10% first insurance surcharge on policy base premium");
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up discount on second and subsequent contracts");
    it.todo("does not apply loyalty discount for customer with < 2 years");
  });

