const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const BLOCK_PREMIUM = 60;
const BLOCK_SIZE = 3;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

function calculateComponentPremium(items: any[]): number {
  const counts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts[item.type] = (counts[item.type] ?? 0) + 1;
    }
  }
  let premium = 0;
  for (const count of Object.values(counts)) {
    if (count === BLOCK_SIZE) {
      premium += BLOCK_PREMIUM;
    } else {
      premium += count * COMPONENT_PREMIUM;
    }
  }
  return premium;
}

function calculateItemPremium(item: any): number {
  if (COMPONENT_TYPES.has(item.type)) {
    return 0;
  }
  const base = BASE_PREMIUMS[item.type] ?? 0;
  let premium = base;
  if (item.cursed) {
    premium += base * 0.5;
  }
  if (item.enchantment >= 5) {
    premium += base * 0.3;
  }
  return premium;
}

function calculateNonComponentBasePremium(items: any[]): number {
  return items
    .filter((item: any) => !COMPONENT_TYPES.has(item.type))
    .reduce((sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
}

function calculateQuotePremium(items: any[], customer: any): number {
  const itemTotal = items.reduce((sum, item) => sum + calculateItemPremium(item), 0);
  const componentTotal = calculateComponentPremium(items);
  const policyBase = calculateNonComponentBasePremium(items) + componentTotal;
  const firstInsurance = policyBase * 0.1;
  const loyalty = customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
  return Math.ceil(PROCESSING_FEE + itemTotal + componentTotal + firstInsurance - loyalty);
}

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      return { premium: calculateQuotePremium(step.items, scenario.customer) };
    }
  });
  return { results };
}

import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("returns premium of 5 G for an empty item list (processing fee only)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("returns correct base premium for a single sword (100 G + 5 G fee = 105 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 115 }); // 100 + 10 first insurance + 5 fee
    });
    it("returns correct base premium for a single amulet (60 G + 5 G fee = 65 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 71 }); // 60 + 6 first insurance + 5 fee
    });
    it("returns correct base premium for a single staff (80 G + 5 G fee = 85 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 93 }); // 80 + 8 first insurance + 5 fee
    });
    it("returns correct base premium for a single potion (40 G + 5 G fee = 45 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 49 }); // 40 + 4 first insurance + 5 fee
    });
    it("returns correct base premium for a single component (25 G + 5 G fee = 30 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 33 }); // 25 + 2.5 rounds up to 3 + 5 fee
    });
    it("sums base premiums for multiple items in a policy", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 181 }); // 160 + 16 first insurance + 5 fee
    });
  });

  describe("Quote - component blocks", () => {
    it("charges 50 G for 2 runes (no block)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 60 }); // 50 + 5 first insurance + 5 fee
    });
    it("charges 60 G for exactly 3 alike components (block applies)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 71 }); // 60 block + 6 first insurance + 5 fee
    });
    it("charges 100 G for 4 runes (no block — block requires exactly 3)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" }, { type: "rune" },
              { type: "rune" }, { type: "rune" },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 115 }); // 100 + 10 first insurance + 5 fee
    });
    it("charges 75 G for 2 runes + 1 moonstone (no block: different types)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 88 }); // 75 + 7.5 rounds up to 8 + 5 fee
    });
    it("charges 120 G for 3 runes + 3 moonstones (two separate blocks)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" }, { type: "rune" }, { type: "rune" },
              { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 137 }); // 120 + 12 first insurance + 5 fee
    });
    it("charges 175 G for 7 runes (no blocks apply)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: Array.from({ length: 7 }, () => ({ type: "rune" })),
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 198 }); // 175 + 17.5 rounds up to 18 + 5 fee
    });
  });

  describe("Quote - item-specific modifiers", () => {
    it("adds 50% cursed surcharge on the cursed item's base premium only", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // 100 sword + 50 curse + 60 amulet = 210 items + 16 first insurance (10% of 160) + 5 fee = 231
      expect(result.results[0]).toEqual({ premium: 231 });
    });
    it("adds 30% high-enchantment surcharge for enchantment level >= 5", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // 100 + 30 enchantment + 10 first insurance + 5 fee = 145
      expect(result.results[0]).toEqual({ premium: 145 });
    });
    it("applies both cursed and high-enchantment surcharges on the same item", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: true },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // 100 + 50 curse + 30 enchantment + 10 first insurance + 5 fee = 195
      expect(result.results[0]).toEqual({ premium: 195 });
    });
    it("does not add high-enchantment surcharge for enchantment level 4", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 4, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // 100 + 10 first insurance + 5 fee = 115
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("applies item-specific surcharges only to affected items in multi-item policy", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 6, cursed: false },
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // 80 + 24 enchantment + 40 potion + 12 first insurance (10% of 120) + 5 fee = 161
      expect(result.results[0]).toEqual({ premium: 161 });
    });
  });

  describe("Quote - policy-wide modifiers", () => {
    it("adds 10% first insurance surcharge on policy base premium", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // 100 base + 10 first insurance (10% of 100) + 5 fee = 115
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("applies 20% loyalty discount for customer with >= 2 years", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 3 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // 100 base + 10 first insurance - 20 loyalty (20% of 100) + 5 fee = 95
      expect(result.results[0]).toEqual({ premium: 95 });
    });
    it.todo("applies 15% follow-up discount on second and subsequent contracts");
    it.todo("does not apply loyalty discount for customer with < 2 years");
  });

  describe("Quote - integration: modifier stacking", () => {
    it.todo("newcomer with cursed sword: 100 + 50 curse + 10 first = 160 + 5 fee = 165 G");
    it.todo("long-standing second contract cursed enchanted sword: 100 + 50 + 30 - 20 + 10 - 15 = 155 + 5 = 160 G");
    it.todo("rounds premium up in MHPCO's favor");
  });

  describe("Quote - error handling", () => {
    it.todo("rejects unknown item type with an error");
  });

  describe("Claim - standard reimbursement", () => {
    it.todo("reimburses damage minus 100 G deductible for a standard item");
    it.todo("applies deductible per damaged item in same event");
    it.todo("reimburses damage to a component minus deductible");
  });

  describe("Claim - special clauses", () => {
    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
    it.todo("fully reimburses dragon-material items minus deductible");
    it.todo("applies 50% rule when item is both dragon-material and enchantment >= 8");
    it.todo("fully reimburses dragon-material with enchantment < 8 minus deductible");
  });

  describe("Claim - cap tracking", () => {
    it.todo("caps total payout at 2x insurance sum per policy");
    it.todo("tracks remaining cap across multiple claims on same policy");
    it.todo("reduces payout to remaining cap when cap is nearly exhausted");
  });

  describe("Claim - error handling", () => {
    it.todo("rejects claim referencing item not in the policy");
    it.todo("rejects claim with negative damage amount");
    it.todo("rejects claim with more damages of a type than policy covers");
  });
});

